!function(){return function e(t,n,r){function a(i,s){if(!n[i]){if(!t[i]){var l="function"==typeof require&&require;if(!s&&l)return l(i,!0);if(o)return o(i,!0);var d=new Error("Cannot find module '"+i+"'");throw d.code="MODULE_NOT_FOUND",d}var c=n[i]={exports:{}};t[i][0].call(c.exports,function(e){return a(t[i][1][e]||e)},c,c.exports,e,t,n,r)}return n[i].exports}for(var o="function"==typeof require&&require,i=0;i<r.length;i++)a(r[i]);return a}}()({1:[function(e,t,n){"use strict";Object.defineProperty(n,"__esModule",{value:!0}),n.growthMarketingCoordinator=void 0;n.growthMarketingCoordinator={title:"Growth Marketing Coordinator",header:'\n    <p>\n    Level: 1<br> \n    Reports to: Growth Marketing Coordinator<br> \n    Department: Site & Growth Marketing<br> \n    Reports: None<br> \n    FLSA Status: Non-Exempt<br> \n    Employee: TBD\n    </p>\n\n    <h5>\n    To be considered for this role, please complete the Google Form Application here:\n    </h5>\n\n    <p>\n    <a href="https://forms.gle/AhgpUnuKC7odmVyv8" target="_blank">https://forms.gle/AhgpUnuKC7odmVyv8</a>\n    </p>\n\n    <h3>Position Overview</h3>\n    \n    <p>\n    We’re looking for a Marketing Coordinator to help keep Tea Collection’s marketing efforts organized, on track, and running smoothly. This role supports the execution and optimization of our marketing programs across digital advertising and print catalogs.\n    </p>\n\n    <p>\n    You’ll work closely with Marketing, Creative, Site, Product, and external partners to support campaign execution, performance tracking, and testing. This is a great opportunity for someone who enjoys both creative and analytical work, thrives in a fast-paced environment, and wants to grow hands-on marketing experience with strong mentorship.\n    </p>\n\n    <p>\n    This is a hybrid role. Bay Area–based team members work from our Emeryville office at least one day per week. Remote team members are expected to travel to the office at least twice a year. The Coordinator must be accessible via video and messaging platforms during standard Pacific Time business hours.\n    </p>\n\n',pay:"\n    <h3>Pay Range:</h3>\n    <p>$53,000-58,000 Salary</p>\n    ",duties:[{header:"Campaign Execution & Coordination:",list:["Support the day-to-day execution of marketing campaigns across digital advertising and catalogs. Partner with Creative and cross-functional teams to ensure assets are planned, delivered, and launched accurately and on time."]},{header:"Channel & Partner Support:",list:["Coordinate with external partners such as advertising platform representatives and catalog vendors to ensure timelines, assets, and execution are aligned."]},{header:"Testing & Optimization:",list:["Support testing across creative, copy, and targeting strategies. Track results and help summarize learnings to inform future optimizations and improvements."]},{header:"Reporting & Performance Analysis:",list:["Pull and organize weekly, monthly, and quarterly performance data across marketing channels. Support reporting and hindsighting to help the team understand trends, pacing, and opportunities."]},{header:"Project & Process Management:",list:["Help keep marketing calendars, trackers, timelines, and documentation organized and up to date. Support smooth collaboration across teams by ensuring clarity, alignment, and follow-through on campaign deliverables."]}],who:["Curious, organized, and excited to grow in the marketing space","A proactive problem-solver and clear communicator","Equally comfortable with both creative and analytical tasks","Detail-oriented with strong organizational skills","Thrive in fast-paced, collaborative environments"],qualifications:["0–2 years of experience in digital marketing, eCommerce, or a related role","Hands-on experience with paid media platforms (Meta Ads + Google Ads)","Proficient using Excel/Google Sheets for data tracking and reporting","Bachelor's degree in Marketing, Advertising, or related with a strong academic track record"],footer:"\n    <h3>Expectations for All Employees:</h3>\n    \n    <p>\n    Supports Tea Collection’s mission, vision, and values by embodying excellence and competence, collaboration, innovation, respect, personalization, community commitment, and accountability.\n    </p>\n    \n    <p>\n    Note: Nothing in this job description restricts management’s right to assign or reassign duties and responsibilities to this job at any time. Tea Collection  is an Equal Opportunity Employer. We celebrate diversity and are committed to creating an inclusive environment for all employees. We do not discriminate based upon race, religion, color, national origin, sex, sexual orientation, gender identity, age, status as a protected veteran, status as an individual with a disability, or other applicable legally protected characteristics.\n    </p>\n    "}},{}],2:[function(e,t,n){"use strict";Object.defineProperty(n,"__esModule",{value:!0}),n.jobs=void 0;var r=e("./job-descriptions/growth-marketing-coordinator.js");n.jobs=[r.growthMarketingCoordinator]},{"./job-descriptions/growth-marketing-coordinator.js":1}]},{},[2]);